import{_ as t,o as a,c as r,a3 as i}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"170. Overtime In Lieu","description":"","frontmatter":{"title":"170. Overtime In Lieu","eba":"Mental Health Services 2024-2028","topics":["hours","overtime","wages"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/170-overtime-in-lieu.md","filePath":"ebas/mental-health/support-services/preliminary/170-overtime-in-lieu.md"}'),o={name:"ebas/mental-health/support-services/preliminary/170-overtime-in-lieu.md"};function n(s,e,l,m,p,h){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="_170-overtime-in-lieu" tabindex="-1">170. Overtime In Lieu <a class="header-anchor" href="#_170-overtime-in-lieu" aria-label="Permalink to &quot;170. Overtime In Lieu&quot;">​</a></h1><p><strong>170.1</strong> An Employee may elect, with the consent of the Employer, to take time off in lieu of payment for overtime at a time or times agreed with the Employer.</p><p><strong>170.2</strong> Overtime taken as time off during ordinary time hours shall be taken at the penalty time rate. That is, one- and one-half hours off or two hours off, as the case may be, for each overtime hour worked.</p><p><strong>170.3</strong> An Employer shall provide payment at the appropriate overtime rate where time off in lieu has not been taken within four (4) weeks of accrual.</p><p><strong>170.4</strong> For the purposes of this clause, in accruing or calculating payment of overtime, each period of overtime shall stand alone.</p><p>Plain language terms: OT, extra hours, time and a half, double time, additional hours.</p>',6)])])}const f=t(o,[["render",n]]);export{c as __pageData,f as default};
